import React, { useState } from 'react';
import { itemAPI } from '../services/api';

const StatusTest = () => {
  const [itemId, setItemId] = useState('');
  const [status, setStatus] = useState('MATCHED');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState('');

  const testStatusUpdate = async () => {
    if (!itemId) {
      alert('Please enter an item ID');
      return;
    }

    setLoading(true);
    setResult('Testing status update...');

    try {
      console.log(`Testing status update for item ${itemId} to ${status}`);

      // First, get the current item
      const currentResponse = await itemAPI.getById(itemId);
      console.log('Current item:', currentResponse.data);

      // Update the status
      const updateResponse = await itemAPI.updateStatus(itemId, status);
      console.log('Update response:', updateResponse.data);

      setResult(`✅ Success! Item ${itemId} updated to ${status}`);

      // Verify the update
      const verifyResponse = await itemAPI.getById(itemId);
      console.log('Verified item:', verifyResponse.data);

    } catch (error) {
      console.error('Status update failed:', error);
      setResult(`❌ Error: ${error.message}`);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="card mb-4">
      <div className="card-header">
        <h5>🧪 Status Update Test</h5>
      </div>
      <div className="card-body">
        <div className="row">
          <div className="col-md-3">
            <input
              type="number"
              className="form-control"
              placeholder="Item ID"
              value={itemId}
              onChange={(e) => setItemId(e.target.value)}
            />
          </div>
          <div className="col-md-3">
            <select
              className="form-select"
              value={status}
              onChange={(e) => setStatus(e.target.value)}
            >
              <option value="PENDING">PENDING</option>
              <option value="MATCHED">MATCHED</option>
              <option value="RETURNED">RETURNED</option>
            </select>
          </div>
          <div className="col-md-3">
            <button
              className="btn btn-primary"
              onClick={testStatusUpdate}
              disabled={loading}
            >
              {loading ? 'Testing...' : 'Test Update'}
            </button>
          </div>
          <div className="col-md-3">
            <div className="alert alert-info">
              {result}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default StatusTest;
